-- =============================================================================n-- Layout Analysis Cache: Cache vision API results for layout imagesn-- =============================================================================nnCREATE TABLE IF NOT EXISTS public.layout_analysis_cache (n  id                uuid        PRIMARY KEY DEFAULT gen_random_uuid(),n  image_hash        text        NOT NULL UNIQUE, -- SHA256 of image data URLn  layout_type       text        NOT NULL CHECK (layout_type IN ('report', 'presentation', 'spreadsheet', 'proposal', 'doc', 'contract')),n  sections          jsonb       NOT NULL DEFAULT '[]'::jsonb,n  color_scheme      jsonb,n  typography        jsonb,n  suggested_base_type text      NOT NULL CHECK (suggested_base_type IN ('doc', 'sheet', 'presentation', 'contract')),n  raw_analysis      jsonb       NOT NULL, -- Full Gemini Vision API responsen  created_at        timestamptz NOT NULL DEFAULT now(),n  expires_at        timestamptz DEFAULT (now() + interval '30 days') -- Auto-expire after 30 daysn);nn-- Index for image hash lookupsnCREATE INDEX IF NOT EXISTS idx_layout_analysis_cache_hash ON public.layout_analysis_cache(image_hash);nn-- RLS policiesnALTER TABLE public.layout_analysis_cache ENABLE ROW LEVEL SECURITY;nn-- Anyone can read cache (layout analysis is anon-safe)nCREATE POLICY "layout_analysis_cache_select_all" ON public.layout_analysis_cachen  FOR SELECT USING (true);nn-- Only authenticated users can create/update cache entriesnCREATE POLICY "layout_analysis_cache_insert_auth" ON public.layout_analysis_cachen  FOR INSERT WITH CHECK (auth.uid() IS NOT NULL);nnCREATE POLICY "layout_analysis_cache_update_auth" ON public.layout_analysis_cachen  FOR UPDATE USING (auth.uid() IS NOT NULL);nn-- Documents table: add layout_template field for storing layout data from imagesnALTER TABLE public.documents ADD COLUMN IF NOT EXISTS layout_template jsonb;nnCOMMENT ON COLUMN public.documents.layout_template IS 'Layout analysis results applied to this document from uploaded reference images';